namespace sv_a3ca23f2e75c470cb86e51df4809b02e.Services;

/// <summary>
/// Scoped per-circuit state that holds the currently selected warehouse.
/// All interactive components on the same page share one instance.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _selectedWarehouseId = AvailableWarehouses[0].Id;

    public string SelectedWarehouseId => _selectedWarehouseId;

    public string SelectedWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _selectedWarehouseId).Name
        ?? _selectedWarehouseId;

    public event Func<Task>? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (_selectedWarehouseId == warehouseId) return;
        _selectedWarehouseId = warehouseId;
        if (OnChange is not null)
            await OnChange.Invoke();
    }
}

namespace sv_a3ca23f2e75c470cb86e51df4809b02e.Services;

/// <summary>
/// Simulates a database query for low-stock item counts.
/// Registered as scoped so each circuit gets its own instance.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate an async database call
        int count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

@rendermode InteractiveServer
@inject Services.WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector d-flex align-items-center">
    <label class="me-2 text-nowrap mb-0 small fw-semibold">Warehouse:</label>
    <select class="form-select form-select-sm" value="@WarehouseState.SelectedWarehouseId"
            @onchange="OnSelectionChanged">
        @foreach (var (id, name) in Services.WarehouseState.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleStateChange;
    }

    private async Task OnSelectionChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
            await WarehouseState.SetWarehouseAsync(newId);
    }

    private async Task HandleStateChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleStateChange;
    }
}

@inject Services.WarehouseState WarehouseState
@inject Services.InventoryAlertService AlertService
@implements IDisposable

@if (_alertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@_alertCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    private int _alertCount;

    /// <summary>
    /// When true, this instance owns a polling timer. Only one instance
    /// (the Dashboard page) should poll; others react via the shared event.
    /// </summary>
    [Parameter] public bool Poll { get; set; }

    /// <summary>
    /// Raised when new alert data arrives so other components can refresh.
    /// </summary>
    public static event Func<int, Task>? OnAlertCountUpdated;

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += HandleWarehouseChange;

        if (Poll)
        {
            OnAlertCountUpdated += HandleExternalUpdate;
            await RefreshAlertCount();
            StartPolling();
        }
        else
        {
            OnAlertCountUpdated += HandleExternalUpdate;
            await RefreshAlertCount();
        }
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await RefreshAlertCount();
                // Notify other AlertBadge instances (e.g., the sidebar badge)
                if (OnAlertCountUpdated is not null)
                    await OnAlertCountUpdated.Invoke(_alertCount);
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task RefreshAlertCount()
    {
        _alertCount = await AlertService.GetLowStockCountAsync(WarehouseState.SelectedWarehouseId);
        await InvokeAsync(StateHasChanged);
    }

    private async Task HandleWarehouseChange()
    {
        await RefreshAlertCount();
        if (Poll && OnAlertCountUpdated is not null)
            await OnAlertCountUpdated.Invoke(_alertCount);
    }

    private async Task HandleExternalUpdate(int count)
    {
        if (!Poll)
        {
            _alertCount = count;
            await InvokeAsync(StateHasChanged);
        }
    }

    public void Dispose()
    {
        StopPolling();
        WarehouseState.OnChange -= HandleWarehouseChange;
        OnAlertCountUpdated -= HandleExternalUpdate;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject Services.WarehouseState WarehouseState
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.SelectedWarehouseName</h5>
        <p class="card-text">
            Currently managing <strong>@WarehouseState.SelectedWarehouseId</strong>.
            Use the warehouse selector in the header to switch sites.
        </p>
        <div class="d-flex align-items-center gap-2 mt-3">
            <span class="fw-semibold">Low-Stock Alerts:</span>
            <AlertBadge Poll="true" />
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChange;
    }

    private async Task HandleWarehouseChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChange;
    }
}

