namespace sv_a3ca23f2e75c470cb86e51df4809b02e.Services;

/// <summary>
/// Scoped event bus that lets the polling AlertBadge push updated counts
/// to non-polling AlertBadge instances within the same circuit.
/// </summary>
public sealed class InventoryAlertNotifier
{
    public int LatestCount { get; private set; }

    public event Func<int, Task>? OnCountUpdated;

    public async Task NotifyAsync(int count)
    {
        LatestCount = count;
        if (OnCountUpdated is not null)
            await OnCountUpdated.Invoke(count);
    }
}

